class Field {
    constructor(selector) {
        this.selector = selector;
        this.element = document.querySelector(selector);
        console.log('[timestat/screentime] Field constructor: selector=', selector, 'element=', !!this.element);
        this.updateMetrics();
    }

    updateMetrics() {
        if (!this.element) return;
        const rect = this.element.getBoundingClientRect();
        this.top = rect.top + window.scrollY;
        this.bottom = rect.bottom + window.scrollY;
        this.height = rect.height;
    }

    isOnScreen(viewport, percentOnScreen) {
        this.updateMetrics();
        // Para 'body' la altura es todo el documento: "50% en pantalla" casi nunca se cumple.
        // Consideramos body siempre visible cuando el documento está cargado.
        if (this.selector === 'body' && this.element === document.body) {
            return true;
        }
        const threshold = this.height * (percentOnScreen / 100);
        const result = (
            this.bottom - threshold > viewport.top &&
            this.top + threshold < viewport.bottom
        );
        return result;
    }
}

export default class ScreenTime {
    constructor(options = {}) {
        console.log('[timestat/screentime] ScreenTime constructor options=', options);
        this.viewport = {
            top: window.scrollY,
            bottom: window.scrollY + window.innerHeight
        };
        this.options = {...ScreenTime.defaults, ...options};
        this.field = new Field(this.options.field.selector);
        this.timer = null;
        this.log = {};
        this.reportTimer = 0;
        this.reportIntervalId = null;
        this.inactivityCounter = 0;
        this.inactivityTimer = 0;
        this.lastReport = 0;
        this.reportInterval = this.options.reportInterval * 1000;
        console.log('[timestat/screentime] reportInterval (ms)=', this.reportInterval, 'inactiveInterval=', this.options.inactiveInterval);
        document.addEventListener("visibilitychange", this.handleVisibilityChange.bind(this));
        window.addEventListener('scroll', this.updateViewport.bind(this));
        window.addEventListener('resize', this.updateViewport.bind(this));
        this.start();
    }

    updateViewport() {
        this.viewport.top = window.scrollY;
        this.viewport.bottom = this.viewport.top + window.innerHeight;
    }

    static get defaults() {
        return {
            fields: [],
            percentOnScreen: 50,
            reportInterval: 10,
            googleAnalytics: false,
            everySecondCallback: function () {
            },
            onInactivity: function () {
            },
            onStart: function () {
            },
            onReport: function () {
            }
        };
    }

    start() {
        console.log('[timestat/screentime] start()');
        if (this.options.onStart) {
            this.options.onStart();
        }
        this.clearTimers();
        this.isActive = true;
        this.timer = setInterval(() => {
            this.checkFields();
            this.inactivityTimer++;
            this.reportTimer++;
            if (this.inactivityTimer >= this.options.inactiveInterval) {
                console.log('[timestat/screentime] intervalo: inactividad alcanzada, reportTimer=', this.reportTimer);
                this.handleInactivity();
            }
            if (this.reportTimer >= this.options.reportInterval) {
                console.log('[timestat/screentime] intervalo: reportTimer alcanzado (>=', this.options.reportInterval, '), llamando report()');
                this.report();
            }
        }, 1000);
        this.addActivityListeners();
    }

    addActivityListeners() {
        const events = ['click', 'scroll', 'mousemove', 'keypress', 'touchstart', 'touchmove', 'wheel'];
        const inactivityEvents = ['beforeunload', 'unload', 'pagehide', 'blur'];
        events.forEach(event => {
            window.addEventListener(event, () => this.resetInactivityTimer());
        });
        inactivityEvents.forEach(event => {
            window.addEventListener(event, () => this.handleInactivity());
        });
    }

    resetInactivityTimer() {
        this.inactivityTimer = 0;
        if (!this.isActive) {
            this.isActive = true;
            this.start();
        }
    }

    handleInactivity() {
        console.log('[timestat/screentime] handleInactivity() — se para el contador por inactividad');
        if (this.options.onInactivity) {
            this.options.onInactivity();
        }
        this.isActive = false;
        this.report();
        this.clearTimers();
    }

    clearTimers() {
        if (this.timer) {
            console.log('[timestat/screentime] clearTimers() — intervalo eliminado, el contador ya no se actualizará');
        }
        clearInterval(this.timer);
        this.timer = null;
    }

    checkFields() {
        if (!this.isActive) {
            return;
        }
        const onScreen = this.field.element ? this.field.isOnScreen(this.viewport, this.options.percentOnScreen) : false;
        if (onScreen) {
            const prev = this.log[this.field.selector] || 0;
            this.log[this.field.selector] = prev + 1;
            if (prev === 0 || this.reportTimer % 5 === 0) {
                console.log('[timestat/screentime] checkFields: en pantalla, contador=', this.log[this.field.selector], 'selector=', this.field.selector);
            }
        }
        if (this.options.everySecondCallback) {
            if (!this._lastLogTick) this._lastLogTick = 0;
            this._lastLogTick++;
            if (this._lastLogTick <= 3 || this._lastLogTick % 10 === 0) {
                console.log('[timestat/screentime] checkFields: llamando everySecondCallback, log=', this.log, 'isActive=', this.isActive);
            }
            this.options.everySecondCallback(this.log);
        }
    }

    report() {
        const elapsed = Date.now() - this.lastReport;
        const shouldReport = elapsed >= 10;
        console.log('[timestat/screentime] report() reportTimer=', this.reportTimer, 'elapsed(ms)=', elapsed, 'shouldReport=', shouldReport, 'log=', this.log);
        if (!shouldReport) {
            console.log('[timestat/screentime] report() SALIDA: no shouldReport');
            return;
        }
        const hasFields = Object.keys(this.log).length > 0;
        console.log('[timestat/screentime] report() hasFields=', hasFields, 'onReport=', !!this.options.onReport);
        if (hasFields && this.options.onReport) {
            console.log('[timestat/screentime] report() llamando onReport con log=', this.log);
            this.options.onReport(this.log);
        }
        this.reportTimer = 0;
        this.lastReport = Date.now();
    }

    handleVisibilityChange() {
        console.log('[timestat/screentime] handleVisibilityChange visibilityState=', document.visibilityState);
        if (document.visibilityState === 'hidden') {
            this.stop();
            this.report();
            return;
        }
        this.start();
    }

    stop() {
        console.log('[timestat/screentime] stop() — pausando contador (pestaña oculta o similar)');
        clearInterval(this.timer);
        this.timer = null;
    }
}
